<?php namespace App\Domains\Electronics\Http\Controllers; use Illuminate\Http\Request; use App\Domains\Electronics\Models\ElectronicProduct; class ElectronicProductController { public function index() { return response()->json(ElectronicProduct::all()); } public function store(Request $request) { $product = ElectronicProduct::create($request->all()); return response()->json($product, 201); } public function show(ElectronicProduct $product) { return response()->json($product); } public function update(Request $request, ElectronicProduct $product) { $product->update($request->all()); return response()->json($product); } public function destroy(ElectronicProduct $product) { $product->delete(); return response()->json(null, 204); } }
